### 動態 form（陣列欄位）

```tsx
import { useForm, useFieldArray } from "react-hook-form";

function ContactsForm() {
    const { register, control, handleSubmit } = useForm({
        defaultValues: {
            name: "",
            contacts: [{ type: "email", value: "" }]
        }
    });

    const { fields, append, remove } = useFieldArray({
        control,
        name: "contacts"
    });

    return (
        <form onSubmit={handleSubmit(onSubmit)}>
            <input {...register("name")} />

            {fields.map((field, index) => (
                <div key={field.id}>
                    <select {...register(`contacts.${index}.type`)}>
                        <option value="email">Email</option>
                        <option value="phone">Phone</option>
                    </select>
                    <input {...register(`contacts.${index}.value`)} />
                    <button type="button" onClick={() => remove(index)}>Remove</button>
                </div>
            ))}

            <button type="button" onClick={() => append({ type: "email", value: "" })}>
                Add Contact
            </button>

            <button type="submit">Save</button>
        </form>
    );
}
```


### Server Actions（Next.js）

```tsx
// app/actions.ts
"use server";

import { z } from "zod";

const Schema = z.object({
    email: z.string().email(),
    password: z.string().min(8)
});

export async function loginAction(formData: FormData) {
    const parsed = Schema.safeParse({
        email: formData.get("email"),
        password: formData.get("password")
    });

    if (!parsed.success) {
        return { error: parsed.error.flatten() };
    }

    await db.login(parsed.data.email, parsed.data.password);
    redirect("/dashboard");
}

// Component
function LoginForm() {
    return (
        <form action={loginAction}>
            <input name="email" type="email" />
            <input name="password" type="password" />
            <button type="submit">Login</button>
        </form>
    );
}

// 沒 JavaScript 也能用！
```


### 常見錯誤


- **用 useState 寫複雜 form**—50 個 state、地獄
- **沒 schema 驗證**—手寫 if-else 散亂
- **onChange 每次都驗**—太煩、用 onBlur
- **沒 submit disable**—點 5 次送 5 個
- **error 訊息技術化**—"ValidationError"
- **iOS auto-zoom**—input font-size 16px+


**☕ 用人話講**

Form 4 心法：(1) **React Hook Form + Zod**—2026 標配 (2) **schema 一處定義**—type + 驗證 + error 一條龍 (3) **onBlur 驗證**—不打擾 (4) **Next.js Server Actions**—漸進採用、無 JS 也能用。





⚡
學習加速器

把這節學到的**馬上應用到一個小東西**—改你自己的部落格、做朋友的個人頁、幫家人做個簡單網頁。實作 1 次比看 10 次效果好。在 Chrome F12 按 Elements 看別的網站怎麼用、邊看邊學。

